# Terraform: 确保 ASG 在多个 AZ 中使用多个实例类型
resource "aws_autoscaling_group" "<example_resource_name>" {
  name               = "<example_resource_name>"
  min_size           = 1
  max_size           = 1
  vpc_zone_identifier = ["<subnet_id_1>", "<subnet_id_2>"] # 关键：不同 AZ 中的子网

  mixed_instances_policy {
    launch_template {
      launch_template_specification {
        launch_template_name = "<example_resource_name>"
        version              = "$Latest"
      }
      override { instance_type = "<INSTANCE_TYPE_1>" } # 关键：每个 AZ 多个实例类型
      override { instance_type = "<INSTANCE_TYPE_2>" } # 关键：每个 AZ 多个实例类型
    }
  }
}
```
